'use client'
import { useState } from 'react'
import { AnimatePresence, motion } from 'framer-motion'

export function CheckoutModal({ total }: { total: number }) {
  const [open, setOpen] = useState(false)
  const [method, setMethod] = useState<'cash' | 'card' | 'ewallet' | null>(null)

  return (
    <>
      <button onClick={() => setOpen(true)} className="w-full px-4 py-3 rounded-2xl glass font-semibold">Checkout ${total.toFixed(2)}</button>
      <AnimatePresence>
        {open && (
          <motion.div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
            <motion.div className="glass rounded-2xl p-5 w-full max-w-md" initial={{ scale: 0.95 }} animate={{ scale: 1 }} exit={{ scale: 0.95 }}>
              <div className="text-lg font-semibold mb-4">Select Payment</div>
              <div className="grid grid-cols-3 gap-3">
                {['cash', 'card', 'ewallet'].map(m => (
                  <button key={m} onClick={() => setMethod(m as any)} className="rounded-xl card p-3 capitalize">{m}</button>
                ))}
              </div>
              <div className="mt-4 flex items-center justify-end gap-2">
                <button onClick={() => setOpen(false)} className="px-3 py-2 rounded-xl glass">Cancel</button>
                <button disabled={!method} className="px-4 py-2 rounded-xl glass font-semibold">{method ? 'Confirm' : 'Choose method'}</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}
