 'use client'
import { useCart, totals } from '@/store/cart'
import { motion } from 'framer-motion'
import { Trash2 } from 'lucide-react'
import { CheckoutModal } from './CheckoutModal'

export function CartSidebar() {
  const items = useCart(s => s.items)
  const remove = useCart(s => s.remove)
  const setQty = useCart(s => s.setQty)
  const discount = useCart(s => s.discount)
  const setDiscount = useCart(s => s.setDiscount)
  const { subtotal, tax, total } = totals(items, discount)

  return (
    <div className="w-96 glass rounded-2xl p-4 space-y-3">
      <div className="text-lg font-semibold">Cart</div>
      <div className="space-y-2 max-h-[50vh] overflow-auto pr-2">
        {items.map(i => (
          <div key={i.id} className="flex items-center justify-between rounded-xl card p-3">
            <div className="flex-1">
              <div>{i.name}</div>
              <div className="text-sm text-text-muted">${i.price.toFixed(2)}</div>
            </div>
            <div className="flex items-center gap-2">
              <input type="number" min={1} value={i.qty} onChange={e => setQty(i.id, Math.max(1, Number(e.target.value)))} className="w-16 rounded-lg glass p-1 text-center" />
              <motion.button whileHover={{ rotate: 8, scale: 1.05 }} onClick={() => remove(i.id)} className="p-2 rounded-lg glass">
                <Trash2 className="size-4" />
              </motion.button>
            </div>
          </div>
        ))}
        {items.length === 0 && <div className="p-3 rounded-xl card">Empty</div>}
      </div>
      <div className="space-y-2 rounded-xl card p-3">
        <div className="flex justify-between"><span>Subtotal</span><span>${subtotal.toFixed(2)}</span></div>
        <div className="flex justify-between"><span>Tax 12%</span><span>${tax.toFixed(2)}</span></div>
        <div className="flex justify-between items-center gap-2">
          <span>Discount</span>
          <input type="number" min={0} value={discount} onChange={e => setDiscount(Math.max(0, Number(e.target.value)))} className="w-24 rounded-lg glass p-1 text-right" />
        </div>
        <div className="flex justify-between font-semibold text-xl"><span>Total</span><span>${total.toFixed(2)}</span></div>
      </div>
      <CheckoutModal total={total} />
    </div>
  )
}
